            {(['English', 'Hindi', 'Assamese'] as SupportedLanguage[]).map(lang => (
                <button
                    key={lang}
                    onClick={() => handleLanguageSwitch(lang)}
                    className={`px-3 py-1.5 rounded-xl text-[10px] font-bold transition-all ${!isAutoDetect && currentLanguage === lang ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-white/5 text-slate-400'}`}
                >
                    {lang.toUpperCase()}
                </button>
            ))}
        </div>

        {/* Voice Visualization */}
        <div className="relative flex items-center justify-center">
            <div className={`absolute inset-0 rounded-full animate-ping bg-green-500/20 ${isSpeaking ? 'opacity-100' : 'opacity-0'}`}></div>
            <div className={`p-5 md:p-6 rounded-full transition-all duration-500 shadow-2xl ${isSpeaking ? 'bg-green-500 scale-110' : 'bg-slate-800'}`}>
                <MicroIcon className={`w-8 h-8 md:w-10 md:h-10 ${isSpeaking ? 'text-white' : 'text-slate-500'}`} />
            </div>

            {/* Audio Wave Visualizer Simulation */}
            {isSpeaking && (
                <div className="absolute -right-16 flex items-center gap-1">
                    {[0, 1, 2].map(i => (
                        <div key={i} className="w-1.5 bg-green-400 rounded-full animate-voice-bar" style={{ animationDelay: `${i * 0.2}s` }}></div>
                    ))}
                </div>
            )}
        </div>

        <div className="text-center space-y-1">
            <p className="text-white text-xs md:text-sm font-bold tracking-widest uppercase">
                {isSpeaking ? 'AI Speaking...' : status === 'active' ? 'Listening & Watching' : 'Starting AI...'}
            </p>
            <p className="text-slate-500 text-[10px] font-medium max-w-[280px]">
                {isAutoDetect 
                    ? "Point camera at document and speak naturally. AI detects language." 
                    : `Currently set to ${currentLanguage}. Point camera at reports.`
                }
            </p>
        </div>

        {/* Action Button */}
        <button 
          onClick={onClose}
          className="w-full max-w-xs py-3.5 bg-white/5 hover:bg-red-500/10 text-slate-400 hover:text-red-400 border border-white/5 hover:border-red-500/30 rounded-2xl font-bold text-sm transition-all active:scale-95 flex items-center justify-center gap-2 group"
        >
          <CloseIcon className="w-4 h-4 group-hover:rotate-90 transition-transform" />
